/**
 * AGRÉGER STATISTIQUES + TABLEAU TECHNICIENS (AFFECTÉS)
 * - Compatible data = [{...}] ou data = [[...]]
 * - Ignore data = [[],[],...]
 * - Statut = champ 12 (2=en cours,3=en attente,4=affecté,5=résolu)  <-- ajustable
 * - SLA late = champ 82 (1 = late)
 * - Technicien = champ 5 (null | id number | [ids])
 * - Map id -> "prenom nom" via items users {id, firstname, realname}
 */

function toInt(v, def = 0) {
  if (v === null || v === undefined || v === "") return def;
  if (typeof v === "number") return Number.isFinite(v) ? v : def;
  const n = parseInt(String(v), 10);
  return Number.isFinite(n) ? n : def;
}

function buildUserMap(allItems) {
  const map = {};
  for (const it of allItems) {
    const j = it?.json;
    // objets user typiques
    if (j && j.id != null && j.totalcount == null) {
      const first = String(j.firstname ?? "").trim();
      const last  = String(j.realname ?? "").trim();
      const full = `${first} ${last}`.trim();
      // IMPORTANT: même si full vide, on garde fallback id (sinon resolveName échoue)
      map[String(j.id)] = full || String(j.id);
    }
  }
  return map;
}

function normalizeTechKeys(raw) {
  if (raw == null) return [];
  if (Array.isArray(raw)) return raw.map(x => String(x).trim()).filter(Boolean);
  if (typeof raw === "number") return [String(raw)];
  const s = String(raw).trim();
  if (!s) return [];
  if (s.includes(",")) return s.split(",").map(x => x.trim()).filter(Boolean);
  return [s];
}

function getField(row, keyNum) {
  if (row == null) return null;
  if (Array.isArray(row)) return row[keyNum] ?? null;
  return row[String(keyNum)] ?? row[keyNum] ?? null;
}

function isValidRow(row) {
  if (!row) return false;
  if (Array.isArray(row)) return row.length > 0;
  return Object.keys(row).length > 0;
}

// Statuts GLPI (selon ton flux)
function statusFromCode(code) {
  const c = toInt(code, null);
  if (c === 2) return "EN_COURS";
  if (c === 3) return "EN_ATTENTE";
  if (c === 4) return "AFFECTE";
  if (c === 5) return "RESOLU";
  return "UNKNOWN";
}

function scoreTraitement(ticketsAffectes, slaLate) {
  if (!ticketsAffectes) return 0;
  const rate = slaLate / ticketsAffectes;
  const score = 100 - (rate * 100);
  return Math.round(score * 10) / 10;
}

const items = $input.all() ?? [];
const userMap = buildUserMap(items);

function resolveName(id) {
  const k = String(id);
  return userMap[k] || k;
}

const today = new Date();
const dateISO = today.toISOString().slice(0, 10);

// Statuts
let enCours = 0, enAttente = 0, affectes = 0, resolus = 0;
let totalTickets = 0;

// Table techniciens (AFFECTE seulement)
const tech = {}; // { "id": { ticketsAffectes, slaLate } }

const notes = [];
const unknownStatusCodes = new Set();

for (const it of items) {
  const j = it?.json ?? {};

  // ✅ On ne traite que les réponses "search/Ticket"
  if (j.totalcount == null || !Array.isArray(j.data)) continue;

  // ✅ Compter seulement si on a au moins une ligne valide (sinon data=[[],[],..] => on skip)
  const validRows = j.data.filter(isValidRow);
  if (validRows.length === 0) continue;

  // ✅ Ici: on calcule le statut en comptant les codes présents dans les lignes
  // (au lieu de prendre seulement la première ligne)
  const statusCounts = { EN_COURS: 0, EN_ATTENTE: 0, AFFECTE: 0, RESOLU: 0, UNKNOWN: 0 };

  for (const row of validRows) {
    const st = statusFromCode(getField(row, 12));
    statusCounts[st] = (statusCounts[st] || 0) + 1;
    if (st === "UNKNOWN") unknownStatusCodes.add(String(getField(row, 12)));
  }

  // ✅ si ta requête est bien filtrée par statut, alors toutes les lignes ont le même statut.
  // On prend donc le statut majoritaire:
  const majorStatus = Object.entries(statusCounts)
    .sort((a, b) => b[1] - a[1])[0]?.[0] || "UNKNOWN";

  const count = toInt(j.totalcount, 0);

  // ✅ totalTickets = somme des tickets de ce bloc (pas users/session_token)
  totalTickets += count;

  if (majorStatus === "EN_COURS") enCours += count;
  else if (majorStatus === "EN_ATTENTE") enAttente += count;
  else if (majorStatus === "AFFECTE") affectes += count;
  else if (majorStatus === "RESOLU") resolus += count;

  // ✅ Si c’est la branche AFFECTE : compter par technicien depuis toutes les lignes valides
  if (majorStatus === "AFFECTE") {
    for (const row of validRows) {
      const techRaw = getField(row, 5);
      const isLate = toInt(getField(row, 82) ?? row.is_late, 0);

      const techIds = normalizeTechKeys(techRaw);
      for (const id of techIds) {
        const key = String(id);
        if (!tech[key]) tech[key] = { ticketsAffectes: 0, slaLate: 0 };
        tech[key].ticketsAffectes += 1;
        if (isLate === 1) tech[key].slaLate += 1;
      }
    }
  }
}

// construire la liste finale
const techniciensStats = Object.entries(tech)
  .map(([id, v]) => {
    const tA = toInt(v.ticketsAffectes, 0);
    const late = toInt(v.slaLate, 0);
    return {
      technicien: resolveName(id),
      technicienId: String(id),         // ✅ utile debug
      ticketsAffectes: tA,
      slaLate: late,
      scoreTraitement: scoreTraitement(tA, late),
    };
  })
  .filter(x => x.ticketsAffectes > 0)
  .sort((a, b) => b.ticketsAffectes - a.ticketsAffectes);

if (unknownStatusCodes.size) {
  notes.push(`Statuts inconnus détectés (champ 12): ${Array.from(unknownStatusCodes).join(", ")}. Ajustez statusFromCode().`);
}
if (Object.keys(userMap).length === 0) {
  notes.push("Aucun mapping utilisateurs trouvé: certains techniciens resteront en IDs.");
}
if (techniciensStats.length === 0) {
  notes.push("Aucun technicien trouvé dans les tickets AFFECTE (vérifiez que data contient bien le champ 5).");
}

return [
  {
    json: {
      date: dateISO,
      statut: { enCours, enAttente, affectes, resolus },
      totalTickets,
      techniciensStats,
      notes,
    },
  },
];

// Analyse des tickets par technicien (robuste)
// - Tickets affectés (statut = Affecté)
// - Tickets SLA dépassés (is_late = 1)
// ⚠️ Selon votre configuration GLPI, l'assignee peut être "users_id_assign" (souvent via un champ/forcedisplay).
// Ici on s'appuie sur votre forcedisplay[2]=5 existant dans "LIST TICKET AFFECTTE PAR USER".

const ticketsAffectes = $node["LIST TICKET AFFECTTE PAR USER"]?.json?.data || [];
const ticketsSLALate  = $node["GET Tickets SLA Dépassés"]?.json?.data || [];

const stats = {};

function extractAssigneeIdAndName(ticket) {
  const assignee = ticket["5"];
  let techId = "non-affecte";
  let techName = "Non affecté";

  if (assignee && typeof assignee === "object") {
    techId = assignee.id ?? assignee["id"] ?? "unknown";
    techName = assignee.name ?? assignee.text ?? assignee["name"] ?? "Technicien";
  } else if (assignee) {
    techId = String(assignee);
    techName = String(assignee);
  }
  return { techId, techName };
}

for (const t of ticketsAffectes) {
  const { techId, techName } = extractAssigneeIdAndName(t);
  if (!stats[techId]) {
    stats[techId] = { id: techId, nom: techName, ticketsAffectes: 0, ticketsSLADepasses: 0 };
  }
  stats[techId].ticketsAffectes += 1;
}

// SLA dépassés par technicien
for (const t of ticketsSLALate) {
  const { techId } = extractAssigneeIdAndName(t);
  if (stats[techId]) stats[techId].ticketsSLADepasses += 1;
}

// KPI simple
const result = Object.values(stats).map(tech => {
  const tauxSLADepasses = tech.ticketsAffectes > 0 ? (tech.ticketsSLADepasses / tech.ticketsAffectes) * 100 : 0;

  let score = 100;
  score -= tech.ticketsSLADepasses * 12; // pénalité
  if (tauxSLADepasses < 5) score += 10;
  else if (tauxSLADepasses < 10) score += 5;

  score = Math.max(0, Math.min(100, Math.round(score)));

  let evaluation = "Excellent";
  if (score < 60) evaluation = "À améliorer";
  else if (score < 75) evaluation = "Moyen";
  else if (score < 90) evaluation = "Bon";

  const chargeTravail =
    tech.ticketsAffectes < 10 ? "Légère" :
    tech.ticketsAffectes < 20 ? "Modérée" :
    tech.ticketsAffectes < 30 ? "Élevée" : "Très élevée";

  return {
    ...tech,
    tauxSLADepasses: tauxSLADepasses.toFixed(1) + "%",
    scorePerformance: score,
    evaluation,
    chargeTravail
  };
}).sort((a,b)=> b.scorePerformance - a.scorePerformance);

return [{ json: { statsTechniciens: result, totalTechniciens: result.length } }];

/**
 * GÉNÉRER RAPPORT GLPI - VERSION TABLEAU HORIZONTAL
 * Style compact, professionnel, orienté rapport
 * Compatible n8n
 */

const items = $input.all() ?? [];

function esc(s) {
  return String(s ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function toInt(v, def = 0) {
  const n = typeof v === "number" ? v : parseInt(String(v ?? ""), 10);
  return Number.isFinite(n) ? n : def;
}

function safeArr(v) {
  return Array.isArray(v) ? v : [];
}

function pickFirst(predicate) {
  return items.find(i => {
    try {
      return predicate(i?.json ?? {});
    } catch {
      return false;
    }
  })?.json ?? null;
}

function formatNumber(n) {
  return new Intl.NumberFormat("fr-FR").format(toInt(n, 0));
}

function percent(value, total) {
  if (!total) return 0;
  return Math.round((value / total) * 1000) / 10;
}

function scoreClass(score) {
  if (score >= 90) return "good";
  if (score >= 60) return "medium";
  return "bad";
}

// --------------------------------------------------
// 1) RÉCUPÉRATION DES DONNÉES
// --------------------------------------------------

const aggregateItem =
  pickFirst(j =>
    j.date ||
    j.totalTickets ||
    j.notes ||
    j.statut ||
    j.slaDepasses ||
    j.backlogPlus7j
  ) || {};

const dateISO = aggregateItem.date || new Date().toISOString().slice(0, 10);
const notes = safeArr(aggregateItem.notes);

const statutItem =
  (aggregateItem.statut ? aggregateItem.statut : null) ||
  pickFirst(j =>
    "enCours" in j ||
    "enAttente" in j ||
    "affectes" in j ||
    "resolus" in j
  ) ||
  {};

const statut = {
  enCours: toInt(statutItem.enCours, 0),
  enAttente: toInt(statutItem.enAttente, 0),
  affectes: toInt(statutItem.affectes, 0),
  resolus: toInt(statutItem.resolus, 0),
};

const totalTickets =
  toInt(aggregateItem.totalTickets, 0) ||
  (statut.enCours + statut.enAttente + statut.affectes + statut.resolus);

// SLA
const slaItem =
  pickFirst(j => "slaDepasses" in j) ||
  pickFirst(j => "ticketsSLADepasses" in j) ||
  pickFirst(j => "count" in j && "data" in j) ||
  {};

let slaDepasses = toInt(aggregateItem.slaDepasses, NaN);
if (!Number.isFinite(slaDepasses)) slaDepasses = toInt(slaItem.slaDepasses, NaN);
if (!Number.isFinite(slaDepasses)) slaDepasses = toInt(slaItem.ticketsSLADepasses, NaN);
if (!Number.isFinite(slaDepasses) && Array.isArray(slaItem.data)) slaDepasses = toInt(slaItem.count, 0);
if (!Number.isFinite(slaDepasses)) slaDepasses = 0;

// backlog
const backlogItem =
  pickFirst(j => "backlogPlus7j" in j) ||
  pickFirst(j => "backlog7j" in j) ||
  pickFirst(j => "anciensTickets" in j) ||
  {};

let backlogPlus7j = toInt(aggregateItem.backlogPlus7j, NaN);
if (!Number.isFinite(backlogPlus7j)) backlogPlus7j = toInt(backlogItem.backlogPlus7j, NaN);
if (!Number.isFinite(backlogPlus7j)) backlogPlus7j = toInt(backlogItem.backlog7j, NaN);
if (!Number.isFinite(backlogPlus7j)) backlogPlus7j = toInt(backlogItem.anciensTickets, 0);

// techniciens
const statsTechItem = pickFirst(j => Array.isArray(j.statsTechniciens));
const techStatsItem = pickFirst(j => Array.isArray(j.techniciensStats));

const flatTechItems = items
  .map(i => i.json || {})
  .filter(j => "ticketsAffectes" in j && ("nom" in j || "id" in j || "technicien" in j));

let rawTechniciens = [];

if (statsTechItem?.statsTechniciens) {
  rawTechniciens = statsTechItem.statsTechniciens;
} else if (techStatsItem?.techniciensStats) {
  rawTechniciens = techStatsItem.techniciensStats;
} else if (flatTechItems.length) {
  rawTechniciens = flatTechItems;
}

const techRows = rawTechniciens
  .map(t => ({
    technicien:
      t.fullName ||
      t.technicien ||
      t.nom ||
      `${t.firstname ?? ""} ${t.realname ?? ""}`.trim() ||
      `ID ${t.id ?? t.technicienId ?? ""}`,
    technicienId: t.id ?? t.technicienId ?? "",
    ticketsAffectes: toInt(t.ticketsAffectes, 0),
    slaLate: toInt(t.slaLate ?? t.ticketsSLADepasses, 0),
    scoreTraitement: toInt(t.scoreTraitement ?? t.scorePerformance, 0),
  }))
  .filter(t => t.ticketsAffectes > 0)
  .sort((a, b) => b.ticketsAffectes - a.ticketsAffectes);

// --------------------------------------------------
// 2) CALCULS
// --------------------------------------------------

const resolus = statut.resolus;
const affectes = statut.affectes;
const enCours = statut.enCours;
const enAttente = statut.enAttente;
const ticketsNonResolus = affectes + enCours + enAttente;

const tauxResolution = percent(resolus, totalTickets);
const tauxSLA = totalTickets
  ? Math.round(((totalTickets - slaDepasses) / totalTickets) * 1000) / 10
  : 0;

// --------------------------------------------------
// 3) BLOCS HTML
// --------------------------------------------------

function topIndicatorsTable() {
  return `
    <div class="section-card">
      <div class="section-title">Indicateurs clés</div>
      <table class="kpi-table">
        <thead>
          <tr>
            <th>Total tickets</th>
            <th>Tickets résolus</th>
            <th>Tickets non résolus</th>
            <th>SLA dépassés</th>
            <th>Backlog &gt; 7 jours</th>
            <th>Techniciens actifs</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td>
              <div class="kpi-number">${formatNumber(totalTickets)}</div>
              <div class="kpi-sub">Volume global</div>
            </td>
            <td>
              <div class="kpi-number">${formatNumber(resolus)}</div>
              <div class="kpi-sub">Taux : ${tauxResolution}%</div>
            </td>
            <td>
              <div class="kpi-number">${formatNumber(ticketsNonResolus)}</div>
              <div class="kpi-sub">À suivre</div>
            </td>
            <td>
              <div class="kpi-number">${formatNumber(slaDepasses)}</div>
              <div class="kpi-sub">Conformité : ${tauxSLA}%</div>
            </td>
            <td>
              <div class="kpi-number">${formatNumber(backlogPlus7j)}</div>
              <div class="kpi-sub">Ancienneté</div>
            </td>
            <td>
              <div class="kpi-number">${formatNumber(techRows.length)}</div>
              <div class="kpi-sub">Avec tickets</div>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  `;
}

function nonResolvedTable() {
  return `
    <div class="section-card section-small">
      <div class="section-title">Situation des tickets non résolus</div>
      <table class="simple-table compact-table narrow-table">
        <thead>
          <tr>
            <th>Statut</th>
            <th style="text-align:right;">Nombre</th>
            <th style="text-align:right;">Part des non résolus</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td>Tickets affectés</td>
            <td style="text-align:right;"><strong>${formatNumber(affectes)}</strong></td>
            <td style="text-align:right;">${percent(affectes, ticketsNonResolus)}%</td>
          </tr>
          <tr>
            <td>Tickets en cours</td>
            <td style="text-align:right;"><strong>${formatNumber(enCours)}</strong></td>
            <td style="text-align:right;">${percent(enCours, ticketsNonResolus)}%</td>
          </tr>
          <tr>
            <td>Tickets en attente</td>
            <td style="text-align:right;"><strong>${formatNumber(enAttente)}</strong></td>
            <td style="text-align:right;">${percent(enAttente, ticketsNonResolus)}%</td>
          </tr>
          <tr class="total-row">
            <td>Total non résolus</td>
            <td style="text-align:right;"><strong>${formatNumber(ticketsNonResolus)}</strong></td>
            <td style="text-align:right;">100%</td>
          </tr>
        </tbody>
      </table>
    </div>
  `;
}

function techTable(rows) {
  return `
    <div class="section-card section-small">
      <div class="section-title">Tickets affectés par technicien</div>
      <div class="section-subtitle">Vue synthétique de la répartition de charge et du niveau de traitement.</div>

      ${
        rows.length
          ? `
          <div class="table-wrap limited">
            <table class="simple-table">
              <thead>
                <tr>
                  <th>Technicien</th>
                  <th style="text-align:right;">Tickets</th>
                  <th style="text-align:center;">SLA late</th>
                  <th style="text-align:right;">Score</th>
                </tr>
              </thead>
              <tbody>
                ${rows.map(r => `
                  <tr>
                    <td class="tech-col">${esc(r.technicien)}</td>
                    <td style="text-align:right;"><strong>${formatNumber(r.ticketsAffectes)}</strong></td>
                    <td style="text-align:center;">
                      <span class="pill ${r.slaLate > 0 ? "pill-danger" : "pill-ok"}">${formatNumber(r.slaLate)}</span>
                    </td>
                    <td style="text-align:right;">
                      <span class="score ${scoreClass(r.scoreTraitement)}">${esc(r.scoreTraitement)}%</span>
                    </td>
                  </tr>
                `).join("")}
              </tbody>
            </table>
          </div>
        `
          : `<div class="empty-box">Aucun technicien avec ticket affecté pour cette journée.</div>`
      }
    </div>
  `;
}

const notesHtml = notes.length
  ? `
    <div class="notes-box">
      <div class="notes-title">Notes</div>
      <ul>
        ${notes.map(n => `<li>${esc(n)}</li>`).join("")}
      </ul>
    </div>
  `
  : "";

// --------------------------------------------------
// 4) HTML FINAL
// --------------------------------------------------

const subject = `Rapport GLPI - ${dateISO} (Tickets: ${totalTickets})`;

const html = `
<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>${esc(subject)}</title>
  <style>
    :root {
      --bg: #f5f7fa;
      --card: #ffffff;
      --line: #e5e7eb;
      --text: #1f2937;
      --muted: #6b7280;
      --primary: #1d4ed8;
      --success-bg: #dcfce7;
      --success-text: #166534;
      --warn-bg: #fef3c7;
      --warn-text: #92400e;
      --danger-bg: #fee2e2;
      --danger-text: #991b1b;
      --shadow: 0 3px 10px rgba(15, 23, 42, 0.05);
      --radius: 12px;
    }

    * { box-sizing: border-box; }

    body {
      margin: 0;
      padding: 18px;
      background: var(--bg);
      color: var(--text);
      font-family: Arial, Helvetica, sans-serif;
    }

    .container {
      max-width: 1020px;
      margin: 0 auto;
    }

    .hero {
      background: var(--card);
      border: 1px solid var(--line);
      border-radius: 14px;
      box-shadow: var(--shadow);
      padding: 16px 18px;
      margin-bottom: 12px;
    }

    .hero h1 {
      margin: 0 0 6px;
      font-size: 22px;
      color: #111827;
    }

    .hero-meta {
      font-size: 12px;
      color: var(--muted);
      margin-bottom: 10px;
    }

    .hero-desc {
      margin: 0;
      font-size: 13px;
      line-height: 1.5;
      color: #374151;
    }

    .hero-desc strong {
      color: #111827;
    }

    .section-card {
      background: var(--card);
      border: 1px solid var(--line);
      border-radius: var(--radius);
      box-shadow: var(--shadow);
      padding: 14px 16px;
      margin-bottom: 12px;
    }

    .section-small {
      padding: 13px 15px;
    }

    .section-title {
      font-size: 15px;
      font-weight: 700;
      color: #111827;
      margin-bottom: 8px;
    }

    .section-subtitle {
      font-size: 12px;
      color: var(--muted);
      margin-bottom: 10px;
    }

    .kpi-table,
    .simple-table {
      width: 100%;
      border-collapse: collapse;
    }

    .kpi-table thead th,
    .simple-table thead th {
      background: #fafafa;
      color: var(--muted);
      font-size: 11px;
      text-transform: uppercase;
      letter-spacing: .03em;
      padding: 10px 10px;
      border-bottom: 1px solid var(--line);
      text-align: left;
    }

    .kpi-table tbody td,
    .simple-table tbody td {
      padding: 10px 10px;
      border-bottom: 1px solid #f1f3f5;
      vertical-align: middle;
      font-size: 13px;
    }

    .kpi-number {
      font-size: 20px;
      font-weight: 700;
      color: #111827;
      line-height: 1.15;
    }

    .kpi-sub {
      margin-top: 3px;
      font-size: 11px;
      color: var(--muted);
    }

    .compact-table {
      max-width: 560px;
    }

    .narrow-table {
      width: 100%;
    }

    .table-wrap.limited {
      max-width: 760px;
    }

    .tech-col {
      max-width: 260px;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }

    .pill,
    .score {
      display: inline-block;
      padding: 4px 8px;
      border-radius: 999px;
      font-size: 11px;
      font-weight: 700;
    }

    .pill-ok {
      background: var(--success-bg);
      color: var(--success-text);
    }

    .pill-danger {
      background: var(--danger-bg);
      color: var(--danger-text);
    }

    .score.good {
      background: var(--success-bg);
      color: var(--success-text);
    }

    .score.medium {
      background: var(--warn-bg);
      color: var(--warn-text);
